# Import necessary libraries
from flask import Flask, request
from collections import Counter

app = Flask(__name__)

# Initialize data structure to store image labels
image_labels = {}

# Endpoint to accept image labels
@app.route('/label', methods=['POST'])
def label_image():
    data = request.get_json()
    image_id = data['image_id']
    label = data['label']

    if image_id in image_labels:
        image_labels[image_id].append(label)
    else:
        image_labels[image_id] = [label]

    return 'Label added successfully'

# Endpoint to aggregate labels using majority voting
@app.route('/aggregate', methods=['GET'])
def aggregate_labels():
    aggregated_labels = {}
    for image_id, labels in image_labels.items():
        majority_label = Counter(labels).most_common(1)[0][0]
        aggregated_labels[image_id] = majority_label

    return aggregated_labels

# Endpoint to train model on labeled data
@app.route('/train', methods=['GET'])
def train_model():
    # Code to train model on labeled data
    return 'Model trained successfully'

if __name__ == '__main__':
    app.run()